// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.HashMap;
import java.util.Map;
import java.util.Random;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Query-level tests for the literal datatype histogram specialization: GROUP BY DATATYPE(?o) with COUNT(*) under
 * FILTER(isLiteral(?o)) collapses into one prefix-run counting scan with per-distinct-value datatype resolution.
 */
public class LmdbDatatypeHistogramTest {

	private static final String EX = "http://example.com/";

	private static final String DATATYPE_HISTOGRAM = "SELECT ?datatype (COUNT(*) AS ?literals) WHERE {\n"
			+ "  ?s ?p ?o .\n"
			+ "  FILTER(isLiteral(?o))\n"
			+ "  BIND(DATATYPE(?o) AS ?datatype)\n"
			+ "}\n"
			+ "GROUP BY ?datatype\n"
			+ "ORDER BY DESC(?literals) ?datatype";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@AfterEach
	public void tearDown() {
		System.clearProperty(LmdbNativeParallelPrefixRuns.PARALLEL_MIN_ESTIMATE_PROPERTY);
		if (repository != null) {
			repository.shutDown();
		}
	}

	@Test
	public void datatypeHistogramCollapsesIntoRunCounting() {
		Map<String, Long> expected = openMixedRepository(0);

		long before = LmdbNativeDatatypeHistogram.RUNS.get();
		assertThat(histogram(DATATYPE_HISTOGRAM)).isEqualTo(expected);
		assertThat(LmdbNativeDatatypeHistogram.RUNS.get()).isGreaterThan(before);
	}

	@Test
	public void datatypeHistogramMatchesInParallel() {
		System.setProperty(LmdbNativeParallelPrefixRuns.PARALLEL_MIN_ESTIMATE_PROPERTY, "0");
		Map<String, Long> expected = openMixedRepository(3000);

		long before = LmdbNativeDatatypeHistogram.RUNS.get();
		assertThat(histogram(DATATYPE_HISTOGRAM)).isEqualTo(expected);
		assertThat(LmdbNativeDatatypeHistogram.RUNS.get()).isGreaterThan(before);
	}

	@Test
	public void missingLiteralGuardFallsBackAndStaysCorrect() {
		openMixedRepository(0);

		long before = LmdbNativeDatatypeHistogram.RUNS.get();
		// without FILTER(isLiteral(?o)) the rows with IRI objects fall into an unbound-datatype group; the
		// specialization must not claim this shape
		Map<String, Long> counts = new HashMap<>();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			for (BindingSet bs : QueryResults.asList(conn.prepareTupleQuery(
					"SELECT ?datatype (COUNT(*) AS ?literals) WHERE {\n"
							+ "  ?s ?p ?o .\n"
							+ "  BIND(DATATYPE(?o) AS ?datatype)\n"
							+ "}\n"
							+ "GROUP BY ?datatype")
					.evaluate())) {
				Value datatype = bs.getValue("datatype");
				counts.put(datatype == null ? "unbound" : datatype.stringValue(),
						((Literal) bs.getValue("literals")).longValue());
			}
		}
		assertThat(counts).containsKey("unbound");
		assertThat(LmdbNativeDatatypeHistogram.RUNS.get()).isEqualTo(before);
	}

	/** Loads mixed-datatype data plus non-literal objects and returns the expected per-datatype statement counts. */
	private Map<String, Long> openMixedRepository(int extraRandomStatements) {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		Map<String, Long> expected = new HashMap<>();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p = vf.createIRI(EX, "p");
			java.util.List<Literal> literals = new java.util.ArrayList<>(java.util.List.of(
					vf.createLiteral("short"),
					vf.createLiteral("a considerably longer string literal that will not be inlined into the id"),
					vf.createLiteral(42),
					vf.createLiteral(42L),
					vf.createLiteral(3.14d),
					vf.createLiteral(true),
					vf.createLiteral("hello", "en"),
					vf.createLiteral(new java.math.BigDecimal("10.5")),
					vf.createLiteral("2024-01-01", vf.createIRI("http://www.w3.org/2001/XMLSchema#date"))));
			int subject = 0;
			for (Literal literal : literals) {
				conn.add(vf.createIRI(EX, "s" + subject++), p, literal);
				expected.merge(literal.getDatatype().stringValue(), 1L, Long::sum);
			}
			// duplicate object values across subjects: run lengths above one
			for (int i = 0; i < 5; i++) {
				conn.add(vf.createIRI(EX, "dup" + i), p, vf.createLiteral(42));
				expected.merge("http://www.w3.org/2001/XMLSchema#int", 1L, Long::sum);
			}
			// non-literal objects must not appear in the histogram
			conn.add(vf.createIRI(EX, "x1"), p, vf.createIRI(EX, "iriObject"));
			conn.add(vf.createIRI(EX, "x2"), p, vf.createBNode());
			Random random = new Random(17);
			for (int i = 0; i < extraRandomStatements; i++) {
				Literal literal = vf.createLiteral(random.nextInt(200));
				conn.add(vf.createIRI(EX, "r" + i), p, literal);
				expected.merge(literal.getDatatype().stringValue(), 1L, Long::sum);
			}
		}
		return expected;
	}

	private Map<String, Long> histogram(String query) {
		Map<String, Long> counts = new HashMap<>();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			for (BindingSet bs : QueryResults.asList(conn.prepareTupleQuery(query).evaluate())) {
				counts.put(bs.getValue("datatype").stringValue(), ((Literal) bs.getValue("literals")).longValue());
			}
		}
		return counts;
	}
}
